namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to BlazorNotifications!"),
            CreateNotification("Your profile was updated."),
            CreateNotification("New comment on your post."),
        });
    }

    /// <summary>Returns all notifications currently available.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > sinceId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally by a hosted service so the polling loop has something to find.
    /// </summary>
    public void SimulateIncoming()
    {
        string[] templates =
        [
            "Deployment succeeded for build #{0}.",
            "User #{0} signed up.",
            "Disk usage alert – server #{0} at 90 %.",
            "Pull request #{0} was merged.",
            "Backup #{0} completed.",
        ];

        var msg = templates[Random.Shared.Next(templates.Length)];
        msg = string.Format(msg, Random.Shared.Next(1000, 9999));

        lock (_lock)
        {
            _notifications.Add(CreateNotification(msg));
        }
    }

    private Notification CreateNotification(string message)
        => new(Id: _nextId++, Message: message, Timestamp: DateTime.UtcNow);
}

namespace BlazorNotifications.Services;

/// <summary>
/// Background hosted service that periodically adds fake notifications
/// so the polling loop on the page has fresh data to discover.
/// </summary>
public class NotificationSimulatorService : BackgroundService
{
    private readonly NotificationService _notifications;

    public NotificationSimulatorService(NotificationService notifications)
        => _notifications = notifications;

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            _notifications.SimulateIncoming();
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@using BlazorNotifications.Services
@inject NotificationService NotificationSvc
@inject PersistentComponentState ApplicationState

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in _notifications.OrderByDescending(x => x.Id))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted text-nowrap ms-3">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistSub;

    protected override void OnInitialized()
    {
        // During SSR this persists the data into the page payload.
        // During interactive init this restores it, avoiding a second fetch.
        _persistSub = ApplicationState.RegisterOnPersisting(PersistNotifications);

        if (ApplicationState.TryTakeFromJson<List<Notification>>(
                nameof(_notifications), out var restored))
        {
            _notifications = restored!;
        }
        else
        {
            _notifications = NotificationSvc.GetAll();
        }
    }

    private Task PersistNotifications()
    {
        ApplicationState.PersistAsJson(nameof(_notifications), _notifications);
        return Task.CompletedTask;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender only fires in the interactive runtime — never during SSR.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            var maxId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
            var newer = NotificationSvc.GetSince(maxId);

            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _persistSub.Dispose();
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

